    [HttpPost]
    public async Task<IActionResult> ForwardWebhook([FromBody] WebhookRequest webhookRequest)
    {
        if (string.IsNullOrEmpty(webhookRequest.TargetUrl))
        {
            return BadRequest("Target URL is required.");
        }

        try
        {
            var response = await _httpClient.SendAsync(
                new HttpRequestMessage(webhookRequest.Method, webhookRequest.TargetUrl)
